#include "tm1637_7seg.h"
#include <TM1637Display.h>
static TM1637Display seg(25,26);
void tm1637_setup(){seg.setBrightness(4);seg.clear();Serial.println("[tm1637] OK");}
void tm1637_show_number(int n){seg.showNumberDec(n,false);}
void tm1637_show_time(uint8_t h,uint8_t m){seg.showNumberDecEx(h*100+m,0x40,true);}
void tm1637_set_brightness(uint8_t b){seg.setBrightness(b);}
void tm1637_clear(){seg.clear();}
